INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'be5341e0-7300-4a1a-a778-9705229cc3b5',
  '00000000-0000-0000-0000-000000000001',
  $escape$ebpf on Monolithic Kernels: A Hybrid Approach$escape$,
  $escape$When working with ebpf on monolithic kernels, developers often face challenges in modifying existing code. To overcome this, Linux provides a hybrid approach, where ebpf programs can be loaded as loadable kernel modules (LKMs). This allows developers to leverage LKM's ability to modify kernel behavior without modifying the core kernel code. In contrast, BSD's monolithic kernel design restricts ebpf's ability to load new code, forcing developers to rely on statically compiled kernel modules. For instance, an ebpf program can be compiled as an LKM and loaded into the Linux kernel using the 'insmod' command.$escape$,
  $escape$BPF_PROG_TYPE_LSM = 1
#include <linux/module.h>
#include <linux/bpf.h>

char *prog_name = "my_lsm_prog";

static int _init(void)
{
	bpf_prog_register(prog_name, BPF_PROG_TYPE_LSM);
	return 0;
}

module_init(_init);
$escape$,
  $escape$c$escape$,
